/**
     * Creates a column with the specified name and data type.
     *
     * @param name
     *            the uppercase column name
     * @param type
     *            the data type
     * @return the column
     */
protected final Column column(String name, TypeInfo type) {
        return new Column(database.sysIdentifier(name), type);
